('startmate-2026-07','startmate_community_sheet','https://docs.google.com/spreadsheets/d/1lIK2Lji83-tO5DlgMHu7KI7WeVzPqL9fFJ2hrNuVaCg','Accelerators',ARRAY[45]::integer[],'{"status": "Active", "name": "Founders 10X", "contact": "Sasha Whittle", "city_country": "Sydney", "investment": "$110K SAFE", "cohort_timing": "Aug-Nov", "focus": "Agnostic, UNSW affiliation", "association": "UNSW Founders", "website": "https://www.founders.unsw.edu.au/10x"}'::jsonb,'accelerator','innovation_ecosystem','related_review','{}'::jsonb,'accelerator:founders10x','f06561ff-d100-45d1-a922-18aaa993260e'::uuid,'innovation','inst_domain','matched innovation.UNSW Health 10X via inst_domain (0.9) — shared institutional domain; likely a sibling program, not a duplicate','high',ARRAY['institutional_domain']::text[],'{"status": "verified", "evidence": "Founders 10X matches innovation.UNSW Health 10X as a sibling program, not a duplicate: ''Founders 10X'' is UNSW Founders'' overarching 10x Accelerator (three streams - All Industries, Health, Climate), while ''Health 10X'' (H10X) is the health-specific stream delivered with The George Institute for Global Health. Both are active in 2026: the UNSW Founders 10x Accelerator (backed 135 startups, $277M raised since 2017) launched its 2026 program with a $100,000 founder-friendly deal, and Health 10X''s 2026 applications have already closed, confirming a live 2026 cohort cycle.", "sources": ["https://www.startupdaily.net/topic/accelerator/unsw-founders-launches-2026-accelerator-with-100000-founder-friendly-startup-deal/", "https://unswfounders.com/health10x-accelerator", "https://www.inside.unsw.edu.au/campus-culture/apply-the-2026-unsw-founders-10x-accelerator-program"], "corrections": {}}'::jsonb,now()),
